#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;fcntl.h&gt;
#include &lt;unistd.h&gt;
#include &lt;sys/mman.h&gt;
#include &lt;sys/stat.h&gt;

int main() {
    // 1. Open the file natively
    int fd = open("massive_database.bin", O_RDWR);
    if (fd == -1) return 1;

    // 2. Query the exact size of the file
    struct stat sb;
    fstat(fd, &sb);
    size_t file_size = sb.st_size;

    // 3. Map the file directly into Virtual RAM
    // We request Read and Write capabilities, and MAP_SHARED so changes hit the disk.
    char *mapped_data = mmap(NULL, file_size, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);

    // DANGER: mmap does NOT return NULL on failure. It returns MAP_FAILED.
    if (mapped_data == MAP_FAILED) {
        perror("mmap failed");
        close(fd);
        return 1;
    }

    // 4. Mutate the file at a specific offset.
    // There is no fseek(). There is no write(). We just alter the array.
    // The OS hardware MMU tracks this memory page as "Dirty".
    mapped_data[1024 * 1024 * 50] = 'X'; // Modify byte at 50MB

    // 5. Force the OS to flush the "Dirty" page physically to the SSD immediately.
    // MS_SYNC guarantees the function blocks until the disk acknowledges the write.
    if (msync(mapped_data, file_size, MS_SYNC) == -1) {
        perror("msync failed");
    }

    // 6. Cleanup memory routing
    munmap(mapped_data, file_size);
    close(fd);

    return 0;
}

