void map_file_chunk() {
    int fd = open("massive_log.txt", O_RDONLY);

    // Engineer only cares about the data starting at byte 5000
    off_t target_offset = 5000;

    // Map 1024 bytes starting at offset 5000
    void *ptr = mmap(NULL, 1024, PROT_READ, MAP_PRIVATE, fd, target_offset);

